    static func questions(topic: HistoryTopic) -> [HistoryQuestion] { all.filter { $0.topic == topic } }

    private static func q(_ id: String, _ nodeId: String, _ knowledgeId: String, _ topic: HistoryTopic, _ prompt: String, _ options: [String], _ answer: Int, _ weapon: HistoryWeapon) -> HistoryQuestion {
        let correct = options[answer]
        return HistoryQuestion(id: id,
                               nodeId: nodeId,
                               knowledgeId: knowledgeId,
                               topic: topic,
                               stage: topic.stage,
                               prompt: prompt,
                               options: options,
                               answerIndex: answer,
                               explanation: explanation(id: id, correct: correct),
                               trapTags: ["时间错位", "概念混淆"],
                               weapon: weapon)
    }

    private static func explanation(id: String, correct: String) -> String {
        switch id {
        case "aq_ac_04":
            return "答案：\(correct)。原因：铁犁牛耕提高了个体家庭独立耕作的能力，使以家庭为单位、男耕女织的小农经济逐渐成为基本经济形态；郡县制取代分封制是政治制度变革，商品经济取代自然经济在中国古代从未真正发生，禅让制更早于春秋战国且与铁犁牛耕无关。"
        case "aq_ac_05":
            return "答案：\(correct)。原因：察举制以孝廉等德才科目为标准，由地方官考察后推荐给中央任用，区别于战国按军功授爵；它不是单纯考试选官（那是科举制的特征），也没有只面向贵族或把选官权完全交给地方豪强（那会脱离中央控制）。"
        case "aq_ac_06":
            return "答案：\(correct)。原因：三省六部制把宰相职权拆分为决策、审核、执行三个环节，相互制约又分工协作，提高了中央决策的科学性和效率；这一制度没有废除宰相制度（宰相职权由三省共同承担），也不涉及地方权力或察举科举之间的替代关系。"
        case "aq_ac_07":
            return "答案：\(correct)。原因：摊丁入亩把原来按人丁征收的丁银摊入田赋一并征收，使赋税征收标准从依赖人丁转向依赖土地财产，并未废除土地税或停止征税；这与战国军功爵制无关。"
        case "aq_ac_08":
            return "答案：\(correct)。原因：商鞅变法废除井田制、开放土地阡陌界限，以法律形式承认土地可以买卖，确立了土地私有制，这是变法在经济基础上的核心突破；它不是恢复分封制（变法恰恰削弱贵族世袭权力），也没有废除赋税或建立科举制（科举制要到隋唐才出现）。"
        case "aq_ac_09":
            return "答案：\(correct)。原因：春秋战国时期铁犁牛耕推动生产力发展，井田制瓦解，社会结构剧烈变动，不同阶层和学派围绕如何治理社会提出不同方案，这才是百家争鸣出现的根本原因；周天子权威此时是削弱而非强化，佛教传入是在两汉之际，科举制更是隋唐才出现，都与百家争鸣的时间不符。"
        case "aq_ac_10":
            return "答案：\(correct)。原因：独尊儒术把儒学教育和官员选拔结合，本质是借助儒学（实际融合了法家集权思想）为大一统帝国提供统一的意识形态支撑，巩固中央集权；它不是简单恢复先秦原始儒学，没有禁止官员学习其他学说，也没有废除察举制（察举制恰恰是独尊儒术后选拔儒生官员的重要途径）。"
        case "aq_ac_11":
            return "答案：\(correct)。原因：河西四郡和西域都护府是汉代经略西域的军政管理机构，它们保障了丝绸之路商路的安全畅通，而丝路联系的加强又巩固了汉代对西域的治理，二者相互支撑；它们不是互不相关的，西域都护府的职能也不限于收取关税，汉代设置这些机构后也没有放弃对西域的管理。"
        case "aq_ac_12":
            return "答案：\(correct)。原因：坊市界限打破意味着商业活动不再受限于特定区域和时间，在城市空间和时间上进一步拓展，是宋代商品经济繁荣的重要表现；这不等于城市规划完全取消，宋代本质仍是小农经济基础上的商业繁荣而非资本主义社会，海外贸易在宋代反而更加发达而非停止。"
        case "aq_ac_13":
            return "答案：\(correct)。原因：元朝疆域空前辽阔，传统地方行政制度难以有效管理，设置行中书省作为中央派出机构统辖地方行政、军事、财政事务，加强了中央对地方的控制；这与恢复分封制、取消地方管理或废除科举制都无关，元朝事实上仍保留了科举制度。"
        case "aq_ac_14":
            return "答案：\(correct)。原因：明朝中后期国内商品经济发展需要更便利的流通货币，同时美洲、日本白银通过海外贸易大量流入中国，两方面共同推动白银成为主要流通货币；明朝并未废除一切货币制度或主动放弃铜钱铸造，郡县制更是与白银货币化无关的古代地方制度。"
        case "aq_ac_15":
            return "答案：\(correct)。原因：黄宗羲等思想家的批判虽然带有早期启蒙色彩，但始终是在儒家思想框架内进行的反思，没有形成系统的近代民主革命纲领，也没有引发实际的政治变革；清朝政府并未采纳这些批判性思想作为治国方针，辛亥革命的直接原因是近代民族危机和资产阶级民主革命思潮，与明清之际思想批判没有直接因果关系。"
        case "aq_ac_01":
            return "答案：\(correct)。原因：郡县制下郡守、县令由中央任免，地方不再像分封制诸侯那样世袭自治，体现官僚政治取代贵族政治，核心指向是中央集权加强。"
        case "aq_ac_02":
            return "答案：\(correct)。原因：科举以考试取士，把选官权更多收归中央，并让寒门士人有上升通道；不能说门第观念彻底消失，也不能把藩镇问题说成由科举完全解决。"
        case "aq_ac_03":
            return "答案：\(correct)。原因：明废丞相、清设军机处都使国家大政更直接服从皇帝意志，判断点是皇权集中；地方分权扩大、科举废除和白银退出都不符合明清史实。"
        case "aq_mc_01":
            return "答案：\(correct)。原因：鸦片战争后中国主权受损、自然经济逐步解体，社会性质开始由独立封建社会转向半殖民地半封建社会；“立即完全解体”“君主专制随即终结”都把渐变说成突变。"
        case "aq_mc_04":
            return "答案：\(correct)。原因：太平天国的绝对平均主义纲领和义和团的盲目排外，都说明农民阶级缺乏科学理论和先进政党领导，难以完成救亡或社会变革任务；二者都不是依靠列强支持发动的，也都没有以建立资本主义制度为目标，太平天国还早于义和团数十年。"
        case "aq_mc_02":
            return "答案：\(correct)。原因：辛亥革命的最大制度成果是结束君主专制、建立共和政体；它没有完成反帝反封建任务，也没有立即实现民族独立或彻底改造经济结构。"
        case "aq_mc_05":
            return "答案：\(correct)。原因：责任内阁制要求内阁对议会负责并对总统形成约束，临时约法借此防止总统（尤其是袁世凯）权力过度集中，体现资产阶级民主分权原则；它与君主专制、传统六部制度或取消中央机构都无关。"
        case "aq_mc_03":
            return "答案：\(correct)。原因：日本全面侵华使民族矛盾压倒阶级矛盾，推动各阶级、党派围绕抗日形成统一战线；“阶级矛盾完全消失”是绝对化表述。"
        case "aq_mc_06":
            return "答案：\(correct)。原因：五四运动中工人阶级以总罢工等形式显示出强大力量，推动革命领导力量从资产阶级、小资产阶级向工人阶级转变，为中国共产党成立奠定阶级基础；五四运动并未完成反帝反封建任务，也没有直接建立社会主义制度或废除封建土地制度。"
        case "aq_mc_07":
            return "答案：\(correct)。原因：土地改革没收地主土地分配给农民，废除了封建土地所有制，调动了农民生产积极性，解放了农村生产力；人民公社、农业社会主义改造发生在土地改革之后，城市国营经济垄断也不是土地改革的内容。"
        case "aq_mc_09":
            return "答案：\(correct)。原因：洋务运动只学习西方器物技术而不变革政治制度，戊戌变法则主张君主立宪等政治制度变革，二者学习西方的层次不同；戊戌变法得到光绪帝和部分官员支持，发生在甲午战争之后，其目标是改良君主制而非推翻清王朝。"
        case "aq_mc_10":
            return "答案：\(correct)。原因：第一次世界大战期间欧洲列强忙于战争，暂时放松了对华经济侵略，加上国内实业救国思潮和政府政策推动，民族资本主义获得短暂发展空间；中国关税并未实现自主，封建经济也并未被彻底废除，外国资本是暂时放松而非主动退出。"
        case "aq_mc_11":
            return "答案：\(correct)。原因：正面战场（主要由国民党军队担负）和敌后战场（主要由中国共产党领导的军队担负）相互配合、相互支援，共同构成了全民族抗战夺取最终胜利的根本保证；二者不是相互对立或互相取代的关系，正面战场的指挥权也始终在国民政府手中。"
        case "aq_mc_12":
